        self.users[user_id].interactions.append(interaction)

    def get_user_interactions(self, user_id):
        if user_id not in self.users:
            return []
        return self.users[user_id].interactions

    def get_interaction_type(self, interaction_type):
        return self.interaction_types.get(interaction_type)

    def anonymize_user_id(self, user_id):
        import hashlib
        return hashlib.sha256(str(user_id).encode()).hexdigest()

    def hash_interaction_data(self, interaction_data):
        import hashlib
        return hashlib.sha256(str(interaction_data).encode()).hexdigest()

