class Anonymizer:
    def __init__(self):
        self.user_ids = {}

    def anonymize(self, user_id):
        if user_id not in self.user_ids:
            hashed_id = hashlib.sha256(str(user_id).encode()).hexdigest()
            self.user_ids[user_id] = hashed_id
        return self.user_ids[user_id]

    def get_real_id(self, anonymized_id):
        for user_id, hashed_id in self.user_ids.items():
            if hashed_id == anonymized_id:
                return user_id
        return None

