from enum import Enum
from typing import Dict, List

class InteractionType(Enum):
    CLICK = 1
    RATING = 2
    UPLOAD = 3
    SETTINGS_CHANGE = 4

class Interaction(ABC):
    def __init__(self, interaction_type: InteractionType, user_id: str, timestamp: datetime):
        self.interaction_type = interaction_type
        self.user_id = user_id
        self.timestamp = timestamp

    @abstractmethod
    def to_dict(self) -> Dict:
        pass

class ClickInteraction(Interaction):
    def __init__(self, user_id: str, timestamp: datetime, page_id: str):
        super().__init__(InteractionType.CLICK, user_id, timestamp)
