            'new_value': self.new_value
        }

class InteractionTracker:
    def __init__(self):
        self.interactions = []

    def add_interaction(self, interaction: Interaction):
        self.interactions.append(interaction)

    def get_interactions(self) -> List[Dict]:
        return [interaction.to_dict() for interaction in self.interactions]

    def anonymize_user_id(self, user_id: str) -> str:
        return hashlib.sha256(user_id.encode()).hexdigest()

    def track_interaction(self, interaction_type: InteractionType, user_id: str, **kwargs):
        user_id = self.anonymize_user_id(user_id)
        if interaction_type == InteractionType.CLICK:
            interaction = ClickInteraction(user_id, datetime.now(), kwargs['page_id'])
        elif interaction_type == InteractionType.RATING:
