        elif interaction_type == InteractionType.UPLOAD:
            interaction = UploadInteraction(user_id, datetime.now(), kwargs['file_id'])
        elif interaction_type == InteractionType.SETTINGS_CHANGE:
            interaction = SettingsChangeInteraction(user_id, datetime.now(), kwargs['setting_name'], kwargs['new_value'])
        else:
