        if user_id in self.users:
            self.users[user_id]['likes'].append(item_id)
            self.interactions[item_id] = self.interactions.get(item_id, 0) + 1

    def rate(self, user_id, item_id, rating):
        if user_id in self.users:
            self.users[user_id]['ratings'][item_id] = rating
            self.interactions[item_id] = self.interactions.get(item_id, 0) + rating

    def upload(self, user_id, item_id):
        if user_id in self.users:
            self.users[user_id]['uploads'].append(item_id)
            self.interactions[item_id] = self.interactions.get(item_id, 0) + 1

    def change_setting(self, user_id, setting, value):
        if user_id in self.users:
            self.users[user_id]['settings'][setting] = value

    def get_interactions(self, item_id):
        return self.interactions.get(item_id, 0)

    def get_user_data(self, user_id):
        return self.users.get(user_id, {})

    def hash_user_id(self, user_id):
        import hashlib
        return hashlib.sha256(str(user_id).encode()).hexdigest()

    def anonymize_user_data(self, user_id):
        user_data = self.get_user_data(user_id)
        anonymized_data = {}
        for key, value in user_data.items():
            if key == 'likes':
                anonymized_data[key] = [self.hash_user_id(like) for like in value]
            elif key == 'ratings':
                anonymized_data[key] = {self.hash_user_id(item): rating for item, rating in value.items()}
            elif key == 'uploads':
                anonymized_data[key] = [self.hash_user_id(upload) for upload in value]
            elif key == 'settings':
                anonymized_data[key] = value
        return anonymized_data

