import uuid
from datetime import datetime

class UserInteraction:
    def __init__(self, user_id, interaction_type, data):
        self.user_id = user_id
        self.interaction_type = interaction_type
        self.data = data
        self.timestamp = datetime.now()

class LocomotiveEngine:
    def __init__(self):
        self.interactions = []
        self.users = {}

    def add_interaction(self, user_id, interaction_type, data):
        interaction = UserInteraction(user_id, interaction_type, data)
        self.interactions.append(interaction)
        if user_id not in self.users:
            self.users[user_id] = []
        self.users[user_id].append(interaction)

    def get_user_interactions(self, user_id):
        return self.users.get(user_id, [])

    def get_interactions_by_type(self, interaction_type):
        return [i for i in self.interactions if i.interaction_type == interaction_type]

    def anonymize_user_id(self, user_id):
        return hashlib.sha256(str(user_id).encode()).hexdigest()

    def hash_data(self, data):
        return hashlib.sha256(str(data).encode()).hexdigest()

class PrivacyCompliance:
    def __init__(self):
        self.locomotive_engine = LocomotiveEngine()

    def add_interaction(self, user_id, interaction_type, data):
        anonymized_user_id = self.locomotive_engine.anonymize_user_id(user_id)
        hashed_data = self.locomotive_engine.hash_data(data)
        self.locomotive_engine.add_interaction(anonymized_user_id, interaction_type, hashed_data)

    def get_user_interactions(self, user_id):
